import { AppAction, AppActions, AppState } from './types';
import { initCardDest, initCardSrc } from '../data';

export const initializeState = (): AppState => {
    return JSON.parse(
        JSON.stringify({
            cardSrc: initCardSrc,
            cardDest: initCardDest,
        }),
    );
};

export const reducer = (state: AppState, action: AppAction): AppState => {
    let cardSrc, cardDest, slotSrc, slotDest;
    switch (action.type) {
        case AppActions.MOVE_CARD:
            cardSrc = [...state.cardSrc];
            cardDest = [...state.cardDest];
            slotSrc = cardSrc
                .concat(cardDest)
                .find((cardSlot) => cardSlot.card?.id === action.cardId);
            slotDest = cardSrc
                .concat(cardDest)
                .find((cardSlot) => cardSlot.id === action.slotId);
            if (slotSrc?.card && slotDest && slotSrc !== slotDest) {
                slotDest.card = { ...slotSrc.card };
                delete slotSrc.card;
            }
            return {
                cardSrc: cardSrc,
                cardDest: cardDest,
            };

        case AppActions.CARDS_CHECK:
            cardSrc = [...state.cardSrc];
            cardDest = [...state.cardDest];
            cardSrc.concat(cardDest).map((cardSlot) => {
                if (cardSlot.card) {
                    cardSlot.card.correct = cardSlot.card.buckets
                        .split(',')
                        .map((c: string) => parseInt(c.trim()))
                        .includes(cardSlot.bucketId);
                }
            });
            return {
                cardSrc: cardSrc,
                cardDest: cardDest,
            };

        case AppActions.CARDS_RESET:
            return initializeState();

        default:
            return state;
    }
};
