export type CardData = {
    id: string;
    buckets: string;
    correct?: boolean;
};

export type CardSlot = {
    id: string;
    bucketId: number;
    card?: CardData;
};

export type AppState = {
    cardSrc: CardSlot[];
    cardDest: CardSlot[];
};

export enum AppActions {
    MOVE_CARD = 'MOVE_CARD',
    CARDS_CHECK = 'CARDS_CHECK',
    CARDS_RESET = 'CARDS_RESET',
}

export type AppAction =
    | {
          type: AppActions.MOVE_CARD;
          cardId: string;
          slotId: string;
      }
    | {
          type: AppActions.CARDS_CHECK;
      }
    | {
          type: AppActions.CARDS_RESET;
      };
