import React, { ReactElement, useReducer } from 'react';
import './App.scss';
import CardList from './components/CardList';
import { initializeState, reducer } from './lib/store';
import { AppActions } from './lib/types';

const App = (): ReactElement => {
    const [state, dispatch] = useReducer(reducer, initializeState());

    return (
        <div className="app">
            <CardList data={state.cardSrc} dispatch={dispatch} />
            <CardList data={state.cardDest} dispatch={dispatch} />
            <div
                style={{
                    display: 'flex',
                    justifyContent: 'center',
                }}
            >
                <button
                    onClick={() => dispatch({ type: AppActions.CARDS_CHECK })}
                >
                    CHECK
                </button>
                <button
                    onClick={() => dispatch({ type: AppActions.CARDS_RESET })}
                >
                    RESET
                </button>
            </div>
        </div>
    );
};
export default App;
