import React, { ReactElement } from 'react';
import './style.scss';
import { CardData } from '../../lib/types';

const Card = ({ cardData }: { cardData: CardData }): ReactElement => {
    const dragstartHandler = (ev: React.DragEvent) => {
        ev.dataTransfer.setData('card-drag', ev.currentTarget.id);
        ev.dataTransfer.dropEffect = 'move';
    };

    const cardClass =
        true === cardData.correct
            ? 'card__single card__single--correct'
            : false === cardData.correct
            ? 'card__single card__single--error'
            : 'card__single';

    return (
        <div
            id={'' + cardData.id}
            onDragStart={dragstartHandler}
            className={cardClass}
            draggable="true"
            data-buckets={cardData.buckets}
        >
            <div className="card__inner">{cardData.buckets}</div>
        </div>
    );
};

export default Card;
