import React, { Dispatch, DragEvent, ReactElement } from 'react';
import './style.scss';
import Card from '../Card';
import { AppAction, AppActions, CardSlot } from '../../lib/types';

const CardList = ({
    data,
    dispatch,
}: {
    data: CardSlot[];
    dispatch: Dispatch<AppAction>;
}): ReactElement => {
    const dragOverHandler = (ev: DragEvent) => {
        ev.preventDefault();
        ev.dataTransfer.dropEffect = 'move';
    };

    const dropHandler = (ev: DragEvent) => {
        ev.preventDefault();
        // const elementToAppend = document.getElementById(elementId) as HTMLElement;
        // if (targetContainer.contains(elementToAppend)) return;
        // targetContainer.appendChild(elementToAppend);
        dispatch({
            type: AppActions.MOVE_CARD,
            cardId: ev.dataTransfer.getData('card-drag'),
            slotId: (ev.target as HTMLDivElement).id,
        });
    };

    return (
        <div className="card-list__wrapper">
            {data.map((cardSlot, idx) => {
                return (
                    <div
                        key={idx}
                        id={'' + cardSlot.id}
                        onDrop={dropHandler}
                        onDragOver={dragOverHandler}
                        className="card-list__inner"
                        data-bucket-id={cardSlot.bucketId}
                    >
                        {cardSlot.card && (
                            <Card key={idx} cardData={cardSlot.card} />
                        )}
                        <p className="debug-msg">{cardSlot.bucketId}</p>
                    </div>
                );
            })}
        </div>
    );
};

export default CardList;
